  ('disabled-6f0ba476-moex-00590', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-110-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'essay', '甲男與乙女結婚後，未約定夫妻財產制。夫妻二人因個性差異甚大而
爭吵不斷，3年後二人協議離婚。甲婚前有積蓄新臺幣（下同）100萬
元，婚後並繼承父親之遺產 300萬元，離婚時其名下之財產有 600 萬
元。乙婚前並無任何財產，其母親於婚後曾贈與200 萬元給她，離婚
時其名下之財產亦有 600 萬元。試問：甲與乙離婚時，二人之財產應
如何分配？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:31+00:00", "source_pdf_sha1": "c8bd1ebd2b10", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "304", "s": "0402", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL)
